[Fact]
public void From_WhenCalledWithPocoCollection_AutomaticallyMapsPropertiesToColumnsAndRows()
{
    // Arrange
    var pocoList = new[]
    {
        new { Id = 101, Name = "Item A", Status = "Active" },
        new { Id = 102, Name = "Item B", Status = "Inactive" }
    };

    // Act
    var table = ConsoleTable.From(pocoList);

    // Assert
    // Verify columns were extracted from the POCO property names
    Assert.Equal(3, table.Columns.Count);
    Assert.Equal("Id", table.Columns[0]);
    Assert.Equal("Name", table.Columns[1]);
    Assert.Equal("Status", table.Columns[2]);

    // Verify rows were populated with the POCO instance values
    Assert.Equal(2, table.Rows.Count);
    Assert.Equal(101, table.Rows[0][0]);
    Assert.Equal("Item A", table.Rows[0][1]);
    Assert.Equal("Active", table.Rows[0][2]);

    Assert.Equal(102, table.Rows[1][0]);
    Assert.Equal("Item B", table.Rows[1][1]);
    Assert.Equal("Inactive", table.Rows[1][2]);
}

[Fact]
public void VerifyTableOutput_SupportsPredefinedFormats_AndConfigurableNumericAlignment()
{
    // Arrange
    var data = new[] { new { Id = 1, Name = "Test" } };
    var table = ConsoleTable.From(data);
    var stringWriter = new System.IO.StringWriter();

    // Configure alignment and redirect output for validation
    table.Configure(options =>
    {
        options.NumberAlignment = Alignment.Right;
        options.OutputTo = stringWriter;
    });

    // Act
    // Exercising a predefined format (MarkDown) as per the business rule requirements
    table.Write(Format.MarkDown);
    var output = stringWriter.ToString();

    // Assert
    // 1. Verify Predefined Format: Ensure Markdown visual markers (pipes and separators) are present
    Assert.Contains("| Id | Name |", output);
    Assert.Contains("|----|------|", output);

    // 2. Verify Configurable Alignment: Numeric column 'Id' should be right-aligned
    // The ID column header is 2 chars. The value '1' is 1 char. 
    // Right alignment (empty string in format) results in "{0,2}" which formats as " 1".
    // The internal format string builds as "| {0,2} | {1,-4} |" based on column lengths.
    Assert.Contains("|  1 | Test |", output);
}

[Fact]
public void AddRow_ShouldThrowException_WhenColumnsAreNotInitializedOrCountIsIncorrect()
{
    var table = new ConsoleTable();

    var exMissing = Assert.Throws<Exception>(() => table.AddRow("data"));
    Assert.Equal("Please set the columns first", exMissing.Message);

    table.AddColumn(new[] { "Column1", "Column2" });

    var exMismatchTooFew = Assert.Throws<Exception>(() => table.AddRow("only_one"));
    Assert.Contains("The number columns in the row (2) does not match the values (1)", exMismatchTooFew.Message);

    var exMismatchTooMany = Assert.Throws<Exception>(() => table.AddRow("one", "two", "three"));
    Assert.Contains("The number columns in the row (2) does not match the values (3)", exMismatchTooMany.Message);

    table.AddRow("valid1", "valid2");
}

[Fact]
public void FromDataTable_ShouldFormatBinaryAsBase64AndApplyNumericRightAlignment()
{
    // Arrange
    var dataTable = new System.Data.DataTable();
    dataTable.Columns.Add("Binary", typeof(byte[]));
    dataTable.Columns.Add("Value", typeof(int));

    var binaryData = new byte[] { 0x48, 0x65, 0x6C, 0x6C, 0x6F };
    var expectedBase64 = Convert.ToBase64String(binaryData);
    dataTable.Rows.Add(binaryData, 1234);

    // Act
    var table = ConsoleTable.From(dataTable);

    // Manually set ColumnTypes and Configure alignment as per the business rule requirements
    table.ColumnTypes = new[] { typeof(byte[]), typeof(int) };
    table.Configure(options => 
    {
        options.NumberAlignment = Alignment.Right;
    });

    table.SetWordBreakDelimiter('|');

    var result = table.ToString();

    // Assert
    // 1. Verify Base64 conversion of binary data (Rule requirement)
    Assert.Contains(expectedBase64, result);

    // 2. Verify numeric alignment logic
    // Based on GetNumberAlignment and ToString logic: 
    // "Value" column is 5 chars wide. "1234" is 4 chars. 
    // Right alignment should produce " 1234" (padding left with a space).
    // Default ToString format is " | {i, alignment length} | "
    Assert.Contains(" 1234 |", result);
}

[Fact]
public void ShouldNotDisplayRowCountWhenEnableCountIsFalse()
{
    var table = new ConsoleTable("Header")
        .AddRow("Value")
        .Configure(o => o.EnableCount = false)
        .ToString();

    Assert.DoesNotContain("Count:", table);
}

[Fact]
public void ShouldNotDisplayRowCountWhenEnableCountIsDisabled()
{
    var options = new ConsoleTableOptions
    {
        Columns = new[] { "Header1", "Header2" },
        EnableCount = false
    };
    var table = new ConsoleTable(options);
    table.AddRow("Data1", "Data2");

    var output = table.ToString();

    Assert.DoesNotContain("Count:", output);
}

[Fact]
public void ColumnAlignmentShouldSupportRightAlignmentForNumericData()
{
    var items = new[]
    {
        new { Id = 1, Name = "Alpha" },
        new { Id = 1000, Name = "Beta" }
    };

    var table = ConsoleTable
        .From(items)
        .Configure(o => o.NumberAlignment = Alignment.Right)
        .ToString();

    // Max length for 'Id' column is 4 (from '1000').
    // Header 'Id' (length 2) aligned right in 4: '  Id'.
    // Row 1 '1' (length 1) aligned right in 4: '   1'.
    // Format string includes a leading space before the value: ' | {0,4} |'.
    // Resulting row part should be '|    1 |' (one space from format + three padding spaces).

    Assert.Contains("|    1 |", table);
    Assert.Contains("| 1000 |", table);
}

[Fact]
public void FromDictionary_ShouldMapOuterKeysToFirstColumnAsRowIdentifiers()
{
    // Arrange
    var data = new Dictionary<string, Dictionary<string, object>>
    {
        {
            "RowID_1", new Dictionary<string, object>
            {
                { "Column_A", "Val1" },
                { "Column_B", 100 }
            }
        },
        {
            "RowID_2", new Dictionary<string, object>
            {
                { "Column_A", "Val2" },
                { "Column_B", 200 }
            }
        }
    };

    // Act
    var table = ConsoleTable.FromDictionary(data);
    var output = table.ToMarkDownString();

    // Assert
    // The implementation of FromDictionary inserts an empty string at index 0 for the header
    // and uses the dictionary key as the first element of each row.
    Assert.Equal("""
                 |         | Column_A | Column_B |
                 |---------|----------|----------|
                 | RowID_1 | Val1     | 100      |
                 | RowID_2 | Val2     | 200      |

                 """, output);
}

