[Fact]
public void From_ShouldGenerateTableFromAllSupportedDataSources()
{
    // 1. List/IEnumerable Source
    var listSource = new List<object> { new { Name = "John", Age = 30 } };
    var tableFromList = ConsoleTable.From(listSource);
    Assert.NotNull(tableFromList);
    Assert.Equal(2, tableFromList.Columns.Count);

    // 2. Object Array Source (First inner array is treated as columns)
    var arraySource = new object[][]
    {
        new object[] { "Header1", "Header2" },
        new object[] { "Value1", "Value2" }
    };
    var tableFromArray = ConsoleTable.From(arraySource);
    Assert.NotNull(tableFromArray);
    Assert.Contains("Header1", tableFromArray.Columns);

    // 3. DataTable Source
    using (var dataTable = new System.Data.DataTable())
    {
        dataTable.Columns.Add("Col1");
        dataTable.Rows.Add("Val1");
        var tableFromDataTable = ConsoleTable.From(dataTable);
        Assert.NotNull(tableFromDataTable);
        Assert.Contains("Col1", tableFromDataTable.Columns);
    }

    // 4. Nested Dictionary Source
    var dictionarySource = new Dictionary<string, Dictionary<string, object>>
    {
        { "Row1", new Dictionary<string, object> { { "ColumnA", true } } }
    };
    var tableFromDictionary = ConsoleTable.FromDictionary(dictionarySource);
    Assert.NotNull(tableFromDictionary);
    Assert.NotEmpty(tableFromDictionary.Columns);
}

[Fact]
        public void Write_ShouldSupportStandardMarkdownAndMinimalFormatsWithCustomRedirect()
        {
            var table = new ConsoleTable("Header");
            table.AddRow("Value");

            // Verify the requirement that it defaults to console standard output
            Assert.Equal(Console.Out, table.Options.OutputTo);

            var stringWriter = new StringWriter();
            table.Configure(o => o.OutputTo = stringWriter);

            // Verify Standard (Default) format can be written to the redirected writer
            table.Write(ConsoleTables.Format.Default);
            var standardOutput = stringWriter.ToString();
            Assert.Contains("Header", standardOutput);

            // Verify MarkDown format can be written to the redirected writer
            table.Write(ConsoleTables.Format.MarkDown);
            var markdownOutput = stringWriter.ToString();
            Assert.Contains("| Header |", markdownOutput);

            // Verify Minimal format can be written to the redirected writer
            table.Write(ConsoleTables.Format.Minimal);
            var minimalOutput = stringWriter.ToString();
            Assert.NotEmpty(minimalOutput);
        }
